VALUES
  ('pukao-d0d1b9a2-moex-00354', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '乙公司於X6年7月初以$270,000購入一台機器，估計耐用年限5年，殘值$20,000，使用直線法 提列折舊與成本模式衡量。X7年底由於經營環境改變，使得該機器之價值有重大跡象顯示已經發 生減損。乙公司於X7年底作減損測試，估計該機器之使用價值為$175,000，公允價值減處分成本 為$165,000，估計耐用年限不變。乙公司X7年應認列之減損損失為？', '["$0", "$14,000", "$20,000", "$30,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00355', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '乙公司 X5 年相關資料如下：購買一台機器付款$75,000，根據關聯企業淨利所認列之投資收益 $55,000，簽發票據$110,000取得一筆土地，發行公司債$260,000。X5年度折舊費用$25,000。X5 年度應收帳款淨額減少$30,000，存貨淨額增加$20,000，應付帳款增加$30,000。X5 年度淨利 $80,000，期初現金餘額$48,000。乙公司X5年的營業活動淨現金流入為？', '["$15,000", "$30,000", "$90,000", "$145,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00356', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '有關公司債，下列敘述何者正確？', '["當公司債為折價發行時，債券的利息費用會逐期增加，折價攤銷數會逐期減少，公司債帳面金 額會逐期增加", "當公司債為溢價發行時，債券的利息費用會逐期降低，溢價攤銷數會逐期增加，公司債帳面金 額會逐期減少", "當公司債為折價發行時，債券的利息費用會逐期降低，折價攤銷數會逐期增加，公司債帳面金 額會逐期增加", "當公司債為溢價發行時，債券的利息費用會逐期增加，溢價攤銷數會逐期減少，公司債帳面金 額會逐期減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00357', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司採定期盤存制，於X1年12月30日收到一筆寄銷人寄銷的商品，甲公司將其列為進貨， 但並未列入期末存貨的盤存數中，該錯誤對於X1年度財務報表有何影響？', '["淨利正確，營運資金不受影響", "淨利低估，營運資金高估", "淨利低估，營運資金低估", "淨利正確，營運資金低估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00358', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司X1年初平價發行公司債$1,000,000，票面利率10%。X1年底資產負債表顯示，資產總額 $2,500,000，流動負債$500,000，權益$1,000,000。X1年度綜合損益表顯示：本期淨利$520,000與 所得稅費用$30,000。請問X1年12月31日甲公司之利息保障倍數為？', '["6.50倍", "5.20倍", "4.80倍", "5.50倍 | 41530"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00359', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X1年初購入一部機器$1,200,000，估計耐用年限6年，無殘值，採直線法提列折舊。於 X3年底認列折舊前，甲公司估計該機器剩餘耐用年限4年，無殘值，但宜自X3年起改採年數合 計法更符合效益消耗型態。請問下列敘述何者正確？（答案四捨五入至元）', '["X3年度之折舊費用為$266,667", "X4年度之折舊費用為$240,000", "X3年底之累計折舊為$600,000", "X4年底之累計折舊為$942,857"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00360', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司在X1年初購入設備，該設備成本$60,000，預估耐用年限為5年，殘值$6,000，採年數合 計法提列折舊並採成本模式後續衡量。X3年初因該設備之運作方式改變，改採直線法提列折舊， 預估耐用年限與殘值均未改變。X3年底該設備之帳面金額應為多少？', '["$14,400", "$20,400", "$21,600", "$27,600"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00361', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司在 X1 年初以成本$5,400,000 取得一棟商辦大樓，並將該大樓予以出租，每年租金為 $300,000。甲公司預估大樓使用年限為50年，無殘值，採公允價值模式衡量。若X1年底，該大 樓之公允價值為$5,500,000，假設不考慮所得稅，該大樓對甲公司X1年度之淨利有何影響？', '["淨利增加$192,000", "淨利增加$292,000", "淨利增加$300,000", "淨利增加$400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00362', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '乙公司X1年初成立，乙公司先進先出法下的銷貨成本分別為X1年$170,000、X2年$200,000；淨 利分別為 X1 年$360,000、X2 年$375,000。若乙公司加權平均法下的銷貨成本分別為 X1 年 $165,000、X2年$185,000，則加權平均法下乙公司之X2年淨利為？（不考慮所得稅）', '["$360,000", "$375,000", "$380,000", "$390,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00363', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X1年1月1日買進乙公司五年期，面額$200,000，票面利率8%，每年底付息，非屬購 入或創始之信用減損金融資產之公司債。當日該公司債的公允價值為$255,000，12個月預期信用 損失估計金額為$3,000，甲公司另支付交易成本$4,000。假設甲公司將該公司債分類為按攤銷後成 本衡量之投資，則X1年1月1日該公司債的總帳面金額與攤銷後成本金額分別為？', '["$255,000、$252,000", "$251,000、$255,000", "$259,000、$256,000", "$257,000、$255,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL)
